import { useEffect, useState } from "react";
import api from "../api/axios";
import "./styles/Books.css";

function LibrarianBooks() {

  const genre = localStorage.getItem("genre");
  const role = localStorage.getItem("role");

  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {

    if (role !== "Librarian" || !genre) return;

    const fetchBooks = async () => {
      try {

        // 🔥 get books ONLY from this category
        const res = await api.get(`/books/category/${genre}`);

        setBooks(res.data);

      } catch (err) {
        console.log("Error fetching books:", err);
      }

      setLoading(false);
    };

    fetchBooks();

  }, [genre, role]);

  if (loading) {
    return <p style={{ padding: "40px" }}>Loading books...</p>;
  }

  return (
    <div className="books-page">

      <h1 className="books-title">All {genre} Books</h1>

      {books.length === 0 ? (
        <p>No books found in {genre}.</p>
      ) : (
        <div className="books-grid">

          {books.map((book) => (

            <div key={book._id} className="book-card">

              <img
                src={book.cover}
                alt={book.title}
                className="book-cover"
              />

              <h3>{book.title}</h3>
              <p>{book.author}</p>

            </div>

          ))}

        </div>
      )}

    </div>
  );
}

export default LibrarianBooks;
